1	// Package bead implements the on-disk bead tracker.
2	//
3	// Size envelope (ddx-f8a11202):
4	//
5	// Individual bead fields — description, acceptance, notes, and each event's
6	// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
7	// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
8	// through `bd import`. Writers exceeding the cap are truncated with a
9	// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
10	// preserve the full payload (notably reviewer streams) should persist to a
11	// sidecar artifact under `.ddx/executions/<id>/` and record a path
12	// reference in the event body.
13	//
14	// On the read side, scanners use a 16MB buffer — real-world incidents have
15	// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
16	// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
17	// matches the scanner in the agent package.
18	package bead
19	
20	import (
21		"bufio"
22		"bytes"
23		"context"
24		"crypto/rand"
25		"encoding/hex"
26		"encoding/json"
27		"fmt"
28		"os"
29		"path/filepath"
30		"sort"
31		"strconv"
32		"strings"
33		"time"
34	
35		"github.com/DocumentDrivenDX/ddx/internal/config"
36		gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
37	)
38	
39	// Store manages beads via a pluggable backend.
40	type Store struct {
41		Collection string
42		Dir        string
43		File       string
44		Prefix     string
45		LockDir    string
46		LockWait   time.Duration
47		backend    Backend // nil means use built-in JSONL
48	}
49	
50	type StoreOption func(*Store)
51	
52	// WithCollection selects the logical bead collection. The default collection
53	// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
54	func WithCollection(name string) StoreOption {
55		return func(s *Store) {
56			if cleaned := normalizeCollection(name); cleaned != "" {
57				s.Collection = cleaned
58			}
59		}
60	}
61	
62	// NewStore creates a store with the given directory.
63	// Defaults can be overridden via options or environment.
64	func NewStore(dir string, opts ...StoreOption) *Store {
65		if dir == "" {
66			dir = envOr("DDX_BEAD_DIR", ".ddx")
67		}
68		prefix := envOr("DDX_BEAD_PREFIX", "")
69		if prefix == "" {
70			workingDir := dir
71			if filepath.Base(dir) == ".ddx" {
72				workingDir = filepath.Dir(dir)
73			}
74			if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil && cfg.Bead.IDPrefix != "" {
75				prefix = cfg.Bead.IDPrefix
76			}
77		}
78		if prefix == "" {
79			prefix = detectPrefix()
80		}
81		backendType := envOr("DDX_BEAD_BACKEND", BackendJSONL)
82	
83		s := &Store{
84			Collection: DefaultCollection,
85			Dir:        dir,
86			Prefix:     prefix,
87			LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
88		}
89		for _, opt := range opts {
90			if opt != nil {
91				opt(s)
92			}
93		}
94		s.File = filepath.Join(dir, s.Collection+".jsonl")
95		s.LockDir = filepath.Join(dir, s.Collection+".lock")
96	
97		// Set up external backend if configured
98		switch backendType {
99		case BackendBD, BackendBR:
100			if ext, err := NewExternalBackend(backendType, s.Collection); err == nil {
101				s.backend = ext
102			}
103			// Fall through to JSONL if tool not available
104		}
105	
106		return s
107	}
108	
109	// NewStoreWithBackend creates a store with an explicit backend (for testing).
110	func NewStoreWithBackend(dir string, b Backend) *Store {
111		s := NewStore(dir)
112		s.backend = b
113		return s
114	}
115	
116	// NewStoreWithCollection creates a store for a named logical collection.
117	func NewStoreWithCollection(dir, collection string) *Store {
118		return NewStore(dir, WithCollection(collection))
119	}
120	
121	// Init creates the storage directory and file.
122	func (s *Store) Init() error {
123		if s.backend != nil {
124			return s.backend.Init()
125		}
126		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
127			return fmt.Errorf("bead: init dir: %w", err)
128		}
129		f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
130		if err != nil {
131			return fmt.Errorf("bead: init file: %w", err)
132		}
133		return f.Close()
134	}
135	
136	// GenID generates a unique bead ID with the configured prefix.
137	func (s *Store) GenID() (string, error) {
138		b := make([]byte, 4)
139		if _, err := rand.Read(b); err != nil {
140			return "", fmt.Errorf("bead: gen id: %w", err)
141		}
142		return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
143	}
144	
145	// ReadAll loads all beads from the configured backend.
146	func (s *Store) ReadAll() ([]Bead, error) {
147		return s.ReadAllFiltered(nil)
148	}
149	
150	// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
151	// those for which the predicate returns true. When the predicate is nil every
152	// bead is returned (equivalent to ReadAll). The predicate is applied at the
153	// per-entry parse boundary after fold — matched beads are appended directly to
154	// the return slice without first being held in an intermediate full-corpus
155	// list, so queries that match a small subset avoid materializing the
156	// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
157	func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
158		if s.backend != nil {
159			all, err := s.backend.ReadAll()
160			if err != nil {
161				return nil, err
162			}
163			if pred == nil {
164				return all, nil
165			}
166			out := make([]Bead, 0, len(all))
167			for _, b := range all {
168				if pred(b) {
169					out = append(out, b)
170				}
171			}
172			return out, nil
173		}
174		beads, warnings, err := s.readAllRaw()
175		if err != nil {
176			return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
177		}
178		beads = foldLatestBeads(beads)
179		for _, warning := range warnings {
180			fmt.Fprintln(os.Stderr, warning)
181		}
182		if len(warnings) > 0 && len(beads) > 0 {
183			repaired, repairErr := s.repairJSONL()
184			if repairErr != nil {
185				return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
186			}
187			if repaired {
188				fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
189			}
190		}
191		if len(beads) == 0 && len(warnings) > 0 {
192			return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
193		}
194		if pred == nil {
195			return beads, nil
196		}
197		out := make([]Bead, 0, len(beads))
198		for _, b := range beads {
199			if pred(b) {
200				out = append(out, b)
201			}
202		}
203		return out, nil
204	}
205	
206	func (s *Store) readAllRaw() ([]Bead, []string, error) {
207		data, err := os.ReadFile(s.File)
208		if os.IsNotExist(err) {
209			return nil, nil, nil
210		}
211		if err != nil {
212			return nil, nil, fmt.Errorf("read: %w", err)
213		}
214		beads, warnings, err := parseBeadJSONL(data)
215		if err != nil {
216			return nil, nil, err
217		}
218		return beads, warnings, nil
219	}
220	
221	func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
222		scanner := bufio.NewScanner(bytes.NewReader(data))
223		// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
224		// reviewer stream dumped into events[].body, and bd-exported lines stacking
225		// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
226		// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
227		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
228	
229		var beads []Bead
230		var warnings []string
231		lineNo := 0
232		for scanner.Scan() {
233			lineNo++
234			line := strings.TrimSpace(scanner.Text())
235			if line == "" {
236				continue
237			}
238			b, err := unmarshalBead([]byte(line))
239			if err != nil {
240				warnings = append(warnings, fmt.Sprintf("bead: read line %d: %v", lineNo, err))
241				continue
242			}
243			beads = append(beads, b)
244		}
245		if err := scanner.Err(); err != nil {
246			return nil, nil, fmt.Errorf("scan jsonl: %w", err)
247		}
248		return beads, warnings, nil
249	}
250	
251	func (s *Store) repairJSONL() (bool, error) {
252		var repaired bool
253		err := s.WithLock(func() error {
254			beads, warnings, err := s.readAllRaw()
255			if err != nil {
256				return err
257			}
258			beads = foldLatestBeads(beads)
259			if len(warnings) == 0 || len(beads) == 0 {
260				return nil
261			}
262			backupPath := s.File + ".bak"
263			backupData, err := os.ReadFile(s.File)
264			if err != nil {
265				return fmt.Errorf("read current file: %w", err)
266			}
267			if err := writeAtomicFile(backupPath, backupData); err != nil {
268				return fmt.Errorf("write backup: %w", err)
269			}
270			if err := s.WriteAll(beads); err != nil {
271				return fmt.Errorf("write repaired file: %w", err)
272			}
273			repaired = true
274			return nil
275		})
276		return repaired, err
277	}
278	
279	func foldLatestBeads(beads []Bead) []Bead {
280		if len(beads) == 0 {
281			return nil
282		}
283	
284		latest := make(map[string]Bead, len(beads))
285		lastSeen := make(map[string]int, len(beads))
286		for i, b := range beads {
287			latest[b.ID] = b
288			lastSeen[b.ID] = i
289		}
290	
291		ids := make([]string, 0, len(latest))
292		for id := range latest {
293			ids = append(ids, id)
294		}
295		sort.Slice(ids, func(i, j int) bool {
296			if lastSeen[ids[i]] != lastSeen[ids[j]] {
297				return lastSeen[ids[i]] < lastSeen[ids[j]]
298			}
299			return ids[i] < ids[j]
300		})
301	
302		out := make([]Bead, 0, len(ids))
303		for _, id := range ids {
304			out = append(out, latest[id])
305		}
306		return out
307	}
308	
309	func (s *Store) readAllLatestRaw() ([]Bead, []string, error) {
310		beads, warnings, err := s.readAllRaw()
311		if err != nil {
312			return nil, nil, err
313		}
314		return foldLatestBeads(beads), warnings, nil
315	}
316	
317	// tmpPath returns a unique temp file path in the same directory as path.
318	// Uses pid + 4 random bytes so concurrent processes don't collide.
319	func tmpPath(path string) (string, error) {
320		b := make([]byte, 4)
321		if _, err := rand.Read(b); err != nil {
322			return "", err
323		}
324		return fmt.Sprintf("%s.tmp-%d-%s", path, os.Getpid(), hex.EncodeToString(b)), nil
325	}
326	
327	func writeAtomicFile(path string, data []byte) error {
328		tmp, err := tmpPath(path)
329		if err != nil {
330			return err
331		}
332		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
333		if err != nil {
334			return err
335		}
336		if _, err := f.Write(data); err != nil {
337			f.Close()
338			_ = os.Remove(tmp)
339			return err
340		}
341		if err := f.Sync(); err != nil {
342			f.Close()
343			_ = os.Remove(tmp)
344			return err
345		}
346		if err := f.Close(); err != nil {
347			_ = os.Remove(tmp)
348			return err
349		}
350		if err := os.Rename(tmp, path); err != nil {
351			_ = os.Remove(tmp)
352			return err
353		}
354		return nil
355	}
356	
357	func normalizeCollection(name string) string {
358		name = strings.TrimSpace(name)
359		if name == "" {
360			return DefaultCollection
361		}
362		name = strings.TrimSuffix(name, ".jsonl")
363		return name
364	}
365	
366	// WriteAll writes all beads to the configured backend, sorted by ID.
367	func (s *Store) WriteAll(beads []Bead) error {
368		sort.Slice(beads, func(i, j int) bool {
369			return beads[i].ID < beads[j].ID
370		})
371	
372		if s.backend != nil {
373			return s.backend.WriteAll(beads)
374		}
375	
376		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
377			return fmt.Errorf("bead: mkdir: %w", err)
378		}
379	
380		tmp, err := tmpPath(s.File)
381		if err != nil {
382			return fmt.Errorf("bead: tmp name: %w", err)
383		}
384		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
385		if err != nil {
386			return fmt.Errorf("bead: create tmp: %w", err)
387		}
388	
389		enc := json.NewEncoder(f)
390		enc.SetEscapeHTML(false)
391		for _, b := range beads {
392			data, err := marshalBead(b)
393			if err != nil {
394				f.Close()
395				os.Remove(tmp)
396				return fmt.Errorf("bead: marshal: %w", err)
397			}
398			if _, err := f.Write(data); err != nil {
399				f.Close()
400				os.Remove(tmp)
401				return fmt.Errorf("bead: write: %w", err)
402			}
403			if _, err := f.WriteString("\n"); err != nil {
404				f.Close()
405				os.Remove(tmp)
406				return fmt.Errorf("bead: write newline: %w", err)
407			}
408		}
409	
410		if err := f.Sync(); err != nil {
411			f.Close()
412			os.Remove(tmp)
413			return fmt.Errorf("bead: sync tmp: %w", err)
414		}
415		if err := f.Close(); err != nil {
416			os.Remove(tmp)
417			return fmt.Errorf("bead: close tmp: %w", err)
418		}
419		if err := os.Rename(tmp, s.File); err != nil {
420			os.Remove(tmp)
421			return fmt.Errorf("bead: rename tmp: %w", err)
422		}
423		return nil
424	}
425	
426	// Create adds a new bead. Assigns defaults, validates, then persists.
427	func (s *Store) Create(b *Bead) error {
428		now := time.Now().UTC()
429		if b.ID == "" {
430			id, err := s.GenID()
431			if err != nil {
432				return err
433			}
434			b.ID = id
435		}
436		if b.IssueType == "" {
437			b.IssueType = DefaultType
438		}
439		if b.Status == "" {
440			b.Status = DefaultStatus
441		}
442		b.CreatedAt = now
443		b.UpdatedAt = now
444	
445		// Validate after defaults are applied so hooks see final state
446		if err := s.validateBead(b); err != nil {
447			return err
448		}
449		// Run create hook
450		if err := s.runHook("validate-bead-create", b); err != nil {
451			return err
452		}
453	
454		return s.WithLock(func() error {
455			beads, _, err := s.readAllLatestRaw()
456			if err != nil {
457				return err
458			}
459			// Reject duplicate IDs
460			for _, e := range beads {
461				if e.ID == b.ID {
462					return fmt.Errorf("bead: duplicate id: %s", b.ID)
463				}
464			}
465			// Validate deps reference existing beads
466			depIDs := b.DepIDs()
467			if len(depIDs) > 0 {
468				existing := make(map[string]bool)
469				for _, e := range beads {
470					existing[e.ID] = true
471				}
472				for _, dep := range depIDs {
473					if !existing[dep] {
474						return fmt.Errorf("bead: dependency not found: %s", dep)
475					}
476				}
477			}
478			beads = append(beads, *b)
479			return s.WriteAll(beads)
480		})
481	}
482	
483	// Get retrieves a bead by ID.
484	func (s *Store) Get(id string) (*Bead, error) {
485		beads, err := s.ReadAll()
486		if err != nil {
487			return nil, err
488		}
489		for _, b := range beads {
490			if b.ID == id {
491				return &b, nil
492			}
493		}
494		return nil, fmt.Errorf("bead: not found: %s", id)
495	}
496	
497	// Update modifies a bead by ID. The mutate function receives a pointer to modify.
498	func (s *Store) Update(id string, mutate func(*Bead)) error {
499		return s.WithLock(func() error {
500			beads, _, err := s.readAllLatestRaw()
501			if err != nil {
502				return err
503			}
504			found := false
505			for i := range beads {
506				if beads[i].ID == id {
507					mutate(&beads[i])
508					beads[i].UpdatedAt = time.Now().UTC()
509					// Core validation after mutation
510					if err := s.validateBead(&beads[i]); err != nil {
511						return err
512					}
513					// Run update hook
514					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
515						return err
516					}
517					found = true
518					break
519				}
520			}
521			if !found {
522				return fmt.Errorf("bead: not found: %s", id)
523			}
524			return s.WriteAll(beads)
525		})
526	}
527	
528	// HeartbeatInterval is how often a claim owner should refresh
529	// execute-loop-heartbeat-at while running. Exposed as a variable so tests
530	// can override it.
531	var HeartbeatInterval = 30 * time.Second
532	
533	// HeartbeatTTL is the maximum allowed age of execute-loop-heartbeat-at
534	// before another worker may reclaim the bead. Defaults to 3× HeartbeatInterval.
535	// Exposed as a variable so tests can override it.
536	var HeartbeatTTL = 90 * time.Second
537	
538	// Claim sets a bead to in_progress with claim metadata.
539	// Fails if the bead is already claimed (status == in_progress) with a
540	// fresh heartbeat. A bead whose execute-loop-heartbeat-at is older than
541	// HeartbeatTTL is considered stalled and will be reclaimed atomically.
542	func (s *Store) Claim(id, assignee string) error {
543		return s.ClaimWithOptions(id, assignee, "", "")
544	}
545	
546	// ClaimWithOptions sets a bead to in_progress with extended claim metadata.
547	// session and worktree are optional; machine is derived from os.Hostname().
548	// A stalled in_progress bead (heartbeat older than HeartbeatTTL) is reclaimed
549	// atomically under the store's lock.
550	func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
551		machine, _ := os.Hostname()
552		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
553			machine = envID
554		}
555		return s.WithLock(func() error {
556			beads, _, err := s.readAllLatestRaw()
557			if err != nil {
558				return err
559			}
560			for i := range beads {
561				if beads[i].ID != id {
562					continue
563				}
564				switch beads[i].Status {
565				case StatusOpen:
566					// normal claim path
567				case StatusInProgress:
568					if !heartbeatIsStale(beads[i].Extra) {
569						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
570					}
571					// stalled claim — reclaim atomically below
572				default:
573					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
574				}
575				// Refuse claims on beads parked with last_status=push_failed:
576				// the previous attempt landed locally but `git push` was rejected,
577				// so the local commit history exists only on this machine. Re-running
578				// primary work would duplicate or strand commits. The operator must
579				// clear execute-loop-last-status (e.g. by manually pushing or
580				// resetting) before another attempt is allowed.
581				if last, ok := beads[i].Extra["execute-loop-last-status"].(string); ok && last == "push_failed" {
582					detail, _ := beads[i].Extra["execute-loop-last-detail"].(string)
583					if detail != "" {
584						return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed (%s); clear execute-loop-last-status to retry", id, detail)
585					}
586					return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed; clear execute-loop-last-status to retry", id)
587				}
588				if beads[i].Extra == nil {
589					beads[i].Extra = make(map[string]any)
590				}
591				now := time.Now().UTC()
592				beads[i].Status = StatusInProgress
593				beads[i].Owner = assignee
594				beads[i].UpdatedAt = now
595				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
596				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
597				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
598				if machine != "" {
599					beads[i].Extra["claimed-machine"] = machine
600				}
601				if session != "" {
602					beads[i].Extra["claimed-session"] = session
603				}
604				if worktree != "" {
605					beads[i].Extra["claimed-worktree"] = worktree
606				}
607				if err := s.validateBead(&beads[i]); err != nil {
608					return err
609				}
610				if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
611					return err
612				}
613				return s.WriteAll(beads)
614			}
615			return fmt.Errorf("bead: not found: %s", id)
616		})
617	}
618	
619	// Heartbeat refreshes execute-loop-heartbeat-at on a claimed bead. Returns
620	// an error if the bead is no longer in_progress (e.g., reclaimed by another
621	// worker), allowing the caller to stop its heartbeat loop.
622	func (s *Store) Heartbeat(id string) error {
623		return s.WithLock(func() error {
624			beads, _, err := s.readAllLatestRaw()
625			if err != nil {
626				return err
627			}
628			for i := range beads {
629				if beads[i].ID != id {
630					continue
631				}
632				if beads[i].Status != StatusInProgress {
633					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, beads[i].Status)
634				}
635				if beads[i].Extra == nil {
636					beads[i].Extra = make(map[string]any)
637				}
638				beads[i].Extra["execute-loop-heartbeat-at"] = time.Now().UTC().Format(time.RFC3339Nano)
639				beads[i].UpdatedAt = time.Now().UTC()
640				return s.WriteAll(beads)
641			}
642			return fmt.Errorf("bead: not found: %s", id)
643		})
644	}
