824	func decodeBeadEvents(raw any) []BeadEvent {
825		switch v := raw.(type) {
826		case []BeadEvent:
827			out := make([]BeadEvent, len(v))
828			copy(out, v)
829			return out
830		case []any:
831			out := make([]BeadEvent, 0, len(v))
832			for _, item := range v {
833				m, ok := item.(map[string]any)
834				if !ok {
835					continue
836				}
837				out = append(out, beadEventFromMap(m))
838			}
839			return out
840		case []map[string]any:
841			out := make([]BeadEvent, 0, len(v))
842			for _, item := range v {
843				out = append(out, beadEventFromMap(item))
844			}
845			return out
846		default:
847			return nil
848		}
849	}
