976	// Reopen sets a bead's status back to open, clears claim fields, optionally
977	// appends notes, and records an immutable reopen event — all in one atomic
978	// lock acquisition.
979	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
980		now := time.Now().UTC()
981		return s.WithLock(func() error {
982			beads, _, err := s.readAllLatestRaw()
983			if err != nil {
984				return err
985			}
986			found := false
987			for i := range beads {
988				if beads[i].ID != id {
989					continue
990				}
991				b := &beads[i]
992				b.Status = StatusOpen
993				b.Owner = ""
994				b.UpdatedAt = now
995				if b.Extra == nil {
996					b.Extra = make(map[string]any)
997				}
998				// Clear claim fields
999				delete(b.Extra, "claimed-at")
1000				delete(b.Extra, "claimed-pid")
1001				delete(b.Extra, "claimed-machine")
1002				delete(b.Extra, "claimed-session")
1003				delete(b.Extra, "claimed-worktree")
1004				delete(b.Extra, "execute-loop-heartbeat-at")
1005				// Append notes
1006				if appendNotes != "" {
1007					if b.Notes != "" {
1008						b.Notes = b.Notes + "\n\n" + appendNotes
1009					} else {
1010						b.Notes = appendNotes
1011					}
1012				}
1013				// Record reopen event
1014				var events []BeadEvent
1015				if raw, ok := b.Extra["events"]; ok {
1016					events = decodeBeadEvents(raw)
1017				}
1018				evt := BeadEvent{
1019					Kind:      "reopen",
1020					CreatedAt: now,
1021				}
1022				if reason != "" {
1023					evt.Summary = reason
1024				}
1025				events = append(events, evt)
1026				encoded := make([]map[string]any, 0, len(events))
1027				for _, e := range events {
1028					encoded = append(encoded, map[string]any{
1029						"kind":       e.Kind,
1030						"summary":    e.Summary,
1031						"body":       e.Body,
1032						"actor":      e.Actor,
1033						"created_at": e.CreatedAt,
1034						"source":     e.Source,
1035					})
1036				}
1037				b.Extra["events"] = encoded
1038				if err := s.validateBead(b); err != nil {
1039					return err
1040				}
1041				if err := s.runHook("validate-bead-update", b); err != nil {
1042					return err
1043				}
1044				found = true
1045				break
1046			}
1047			if !found {
1048				return fmt.Errorf("bead: not found: %s", id)
1049			}
1050			return s.WriteAll(beads)
1051		})
1052	}
