1087	// matchesWhere returns true if the bead satisfies all key=value predicates.
1088	// It checks known struct fields first, then falls back to Extra.
1089	func matchesWhere(b Bead, where map[string]string) bool {
1090		for k, v := range where {
1091			var actual string
1092			switch k {
1093			case "id":
1094				actual = b.ID
1095			case "title":
1096				actual = b.Title
1097			case "status":
1098				actual = b.Status
1099			case "issue_type":
1100				actual = b.IssueType
1101			case "owner":
1102				actual = b.Owner
1103			case "assignee":
1104				actual = b.Owner
1105			case "parent":
1106				actual = b.Parent
1107			case "description":
1108				actual = b.Description
1109			case "acceptance":
1110				actual = b.Acceptance
1111			case "notes":
1112				actual = b.Notes
1113			default:
1114				// Fall back to Extra map for unknown/workflow-specific fields
1115				if b.Extra != nil {
1116					if ev, ok := b.Extra[k]; ok {
1117						actual = fmt.Sprintf("%v", ev)
1118					}
1119				}
1120			}
1121			if actual != v {
1122				return false
1123			}
1124		}
1125		return true
1126	}
