1140	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1141	// they are NOT execution-eligible: epic containers, retry cooldown,
1142	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1143	// emits when the execution queue is empty but `ddx bead ready` is not.
1144	type ReadyExecutionBreakdown struct {
1145		SkippedEpics       []string
1146		SkippedOnCooldown  []string
1147		SkippedNotEligible []string
1148		SkippedSuperseded  []string
1149		NextRetryAfter     string
1150	}
1151	
1152	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1153		out := ReadyExecutionBreakdown{}
1154		ready, err := s.Ready()
1155		if err != nil {
1156			return out, err
1157		}
1158		now := time.Now().UTC()
1159		var soonestRetry time.Time
1160		for _, b := range ready {
1161			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1162				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1163					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1164						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1165						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1166							soonestRetry = retryAfter
1167						}
1168						continue
1169					}
1170				}
1171			}
1172			if eligible, ok := b.Extra["execution-eligible"]; ok {
1173				if val, isBool := eligible.(bool); isBool && !val {
1174					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1175					continue
1176				}
1177			}
1178			if sup, ok := b.Extra["superseded-by"]; ok {
1179				if s, isStr := sup.(string); isStr && s != "" {
1180					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1181					continue
1182				}
1183			}
1184		}
1185		if !soonestRetry.IsZero() {
1186			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1187		}
1188		return out, nil
1189	}
