1191	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1192		beads, err := s.ReadAll()
1193		if err != nil {
1194			return nil, err
1195		}
1196		statusMap := make(map[string]string)
1197		for _, b := range beads {
1198			statusMap[b.ID] = b.Status
1199		}
1200	
1201		var ready []Bead
1202		for _, b := range beads {
1203			if b.Status != StatusOpen {
1204				// Surface stalled in_progress beads so a fresh worker can
1205				// reclaim them atomically in Claim().
1206				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1207					// fall through to dependency check below
1208				} else {
1209					continue
1210				}
1211			}
1212			allSatisfied := true
1213			for _, depID := range b.DepIDs() {
1214				if statusMap[depID] != StatusClosed {
1215					allSatisfied = false
1216					break
1217				}
1218			}
1219			if !allSatisfied {
1220				continue
1221			}
1222			if executionOnly {
1223				// Filter by execution-eligible (default true if absent)
1224				eligible, ok := b.Extra["execution-eligible"]
1225				if ok {
1226					if val, isBool := eligible.(bool); isBool && !val {
1227						continue
1228					}
1229				}
1230				// Filter out superseded beads
1231				if sup, ok := b.Extra["superseded-by"]; ok {
1232					if s, isStr := sup.(string); isStr && s != "" {
1233						continue
1234					}
1235				}
1236				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1237					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1238						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1239							continue
1240						}
1241					}
1242				}
1243			}
1244			ready = append(ready, b)
1245		}
1246	
1247		sortBeadsForQueue(ready)
1248	
1249		return ready, nil
1250	}
