1252	// Blocked returns open beads with at least one unclosed dependency.
1253	func (s *Store) Blocked() ([]Bead, error) {
1254		beads, err := s.ReadAll()
1255		if err != nil {
1256			return nil, err
1257		}
1258		statusMap := make(map[string]string)
1259		for _, b := range beads {
1260			statusMap[b.ID] = b.Status
1261		}
1262	
1263		var blocked []Bead
1264		for _, b := range beads {
1265			if b.Status != StatusOpen {
1266				continue
1267			}
1268			for _, depID := range b.DepIDs() {
1269				if statusMap[depID] != StatusClosed {
1270					blocked = append(blocked, b)
1271					break
1272				}
1273			}
1274		}
1275		sortBeadsForQueue(blocked)
1276		return blocked, nil
1277	}
