1279	// BlockedAll returns open beads that are currently not runnable, classified
1280	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1281	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1282	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1283	// that is both dep-blocked and cooldown-parked is reported as dependency-
1284	// blocked, because deps are the stronger blocker.
1285	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1286		beads, err := s.ReadAll()
1287		if err != nil {
1288			return nil, err
1289		}
1290		statusMap := make(map[string]string)
1291		for _, b := range beads {
1292			statusMap[b.ID] = b.Status
1293		}
1294	
1295		now := time.Now().UTC()
1296		var entries []BlockedBead
1297		for _, b := range beads {
1298			if b.Status != StatusOpen {
1299				continue
1300			}
1301	
1302			var unclosed []string
1303			for _, depID := range b.DepIDs() {
1304				if statusMap[depID] != StatusClosed {
1305					unclosed = append(unclosed, depID)
1306				}
1307			}
1308			if len(unclosed) > 0 {
1309				entries = append(entries, BlockedBead{
1310					Bead: b,
1311					Blocker: Blocker{
1312						Kind:           BlockerKindDependency,
1313						UnclosedDepIDs: unclosed,
1314					},
1315				})
1316				continue
1317			}
1318	
1319			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1320			if !ok {
1321				continue
1322			}
1323			retryAfterStr, isStr := retryAfterRaw.(string)
1324			if !isStr || retryAfterStr == "" {
1325				continue
1326			}
1327			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1328			if err != nil || !retryAfter.After(now) {
1329				continue
1330			}
1331			blocker := Blocker{
1332				Kind:           BlockerKindRetryCooldown,
1333				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1334			}
1335			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1336				if s, ok := v.(string); ok {
1337					blocker.LastStatus = s
1338				}
1339			}
1340			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1341				if s, ok := v.(string); ok {
1342					blocker.LastDetail = s
1343				}
1344			}
1345			entries = append(entries, BlockedBead{
1346				Bead:    b,
1347				Blocker: blocker,
1348			})
1349		}
1350	
1351		sort.SliceStable(entries, func(i, j int) bool {
1352			if entries[i].Priority != entries[j].Priority {
1353				return entries[i].Priority < entries[j].Priority
1354			}
1355			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1356				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1357			}
1358			return entries[i].ID < entries[j].ID
1359		})
1360		return entries, nil
1361	}
1362	
1363	func sortBeadsForQueue(beads []Bead) {
1364		sort.SliceStable(beads, func(i, j int) bool {
1365			if beads[i].Priority != beads[j].Priority {
1366				return beads[i].Priority < beads[j].Priority
1367			}
1368			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1369				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1370			}
1371			return beads[i].ID < beads[j].ID
1372		})
1373	}
