1402	// DepAdd adds a dependency: id depends on depID.
1403	func (s *Store) DepAdd(id, depID string) error {
1404		return s.WithLock(func() error {
1405			beads, _, err := s.readAllLatestRaw()
1406			if err != nil {
1407				return err
1408			}
1409			var target *Bead
1410			depExists := false
1411			for i := range beads {
1412				if beads[i].ID == id {
1413					target = &beads[i]
1414				}
1415				if beads[i].ID == depID {
1416					depExists = true
1417				}
1418			}
1419			if target == nil {
1420				return fmt.Errorf("bead: not found: %s", id)
1421			}
1422			if !depExists {
1423				return fmt.Errorf("bead: dependency not found: %s", depID)
1424			}
1425			if id == depID {
1426				return fmt.Errorf("bead: cannot depend on self")
1427			}
1428			if target.HasDep(depID) {
1429				return nil // already exists
1430			}
1431	
1432			// Check for circular dependency
1433			depMap := make(map[string][]string)
1434			for _, b := range beads {
1435				depMap[b.ID] = b.DepIDs()
1436			}
1437			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1438			if hasCycle(depMap, id) {
1439				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1440			}
1441	
1442			target.AddDep(depID, "blocks")
1443			target.UpdatedAt = time.Now().UTC()
1444			return s.WriteAll(beads)
1445		})
1446	}
