1455	// DepTree returns a text representation of the dependency tree.
1456	func (s *Store) DepTree(rootID string) (string, error) {
1457		beads, err := s.ReadAll()
1458		if err != nil {
1459			return "", err
1460		}
1461		byID := make(map[string]*Bead)
1462		for i := range beads {
1463			byID[beads[i].ID] = &beads[i]
1464		}
1465	
1466		if rootID != "" {
1467			target, ok := byID[rootID]
1468			if !ok {
1469				return "", fmt.Errorf("bead: not found: %s", rootID)
1470			}
1471			var sb strings.Builder
1472			// Walk up: show the dependency chain (what this node depends on)
1473			depChain := s.depChainUp(byID, rootID)
1474			if len(depChain) > 0 {
1475				// Print deps as the tree root(s), with the target as their child
1476				for _, depID := range depChain {
1477					if dep, ok := byID[depID]; ok {
1478						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1479					}
1480				}
1481			}
1482			// Print the target node
1483			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1484			// Print dependents (what depends on this node)
1485			var children []string
1486			for _, other := range sortedKeys(byID) {
1487				if byID[other].HasDep(rootID) {
1488					children = append(children, other)
1489				}
1490			}
1491			for _, child := range children {
1492				s.printTree(&sb, byID, child, "  ", true)
1493			}
1494			return sb.String(), nil
1495		}
1496	
1497		// Find roots (beads that have no dependencies themselves)
1498		var roots []string
1499		for _, b := range beads {
1500			if len(b.Dependencies) == 0 {
1501				roots = append(roots, b.ID)
1502			}
1503		}
1504		sort.Strings(roots)
1505	
1506		var sb strings.Builder
1507		for i, root := range roots {
1508			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1509		}
1510		return sb.String(), nil
1511	}
