1513	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1514		b, ok := byID[id]
1515		if !ok {
1516			return
1517		}
1518	
1519		connector := "├── "
1520		if last {
1521			connector = "└── "
1522		}
1523		if prefix == "" {
1524			connector = ""
1525		}
1526	
1527		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1528	
1529		// Find beads that depend on this one (children in the tree)
1530		var children []string
1531		for _, other := range sortedKeys(byID) {
1532			if byID[other].HasDep(id) {
1533				children = append(children, other)
1534			}
1535		}
1536	
1537		childPrefix := prefix
1538		if prefix != "" {
1539			if last {
1540				childPrefix += "    "
1541			} else {
1542				childPrefix += "│   "
1543			}
1544		}
1545	
1546		for i, child := range children {
1547			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1548		}
1549	}
