1560	// validateBead checks core invariants that must hold for any bead (create or update).
1561	func (s *Store) validateBead(b *Bead) error {
1562		if strings.TrimSpace(b.Title) == "" {
1563			return fmt.Errorf("bead: title is required")
1564		}
1565		if b.Priority < MinPriority || b.Priority > MaxPriority {
1566			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
1567		}
1568		if b.Status != StatusOpen && b.Status != StatusInProgress && b.Status != StatusClosed && b.Status != StatusBlocked {
1569			return fmt.Errorf("bead: invalid status: %s", b.Status)
1570		}
1571		// Self-ref check
1572		for _, depID := range b.DepIDs() {
1573			if depID == b.ID && b.ID != "" {
1574				return fmt.Errorf("bead: cannot depend on self")
1575			}
1576		}
1577		return nil
1578	}
