1580	// detectPrefix derives the bead ID prefix from the repository/directory name,
1581	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
1582	// Falls back to DefaultPrefix if detection fails.
1583	func detectPrefix() string {
1584		// Try git repo root name first
1585		cmd := gitpkg.Command(context.Background(), "", "rev-parse", "--show-toplevel")
1586		if out, err := cmd.Output(); err == nil {
1587			root := strings.TrimSpace(string(out))
1588			if root != "" {
1589				return filepath.Base(root)
1590			}
1591		}
1592		// Fall back to current directory name
1593		if wd, err := os.Getwd(); err == nil {
1594			return filepath.Base(wd)
1595		}
1596		return DefaultPrefix
1597	}
