1640	// hasCycle detects cycles in the dependency graph starting from startID.
1641	func hasCycle(deps map[string][]string, startID string) bool {
1642		visited := make(map[string]bool)
1643		stack := make(map[string]bool)
1644	
1645		var visit func(string) bool
1646		visit = func(id string) bool {
1647			visited[id] = true
1648			stack[id] = true
1649	
1650			for _, dep := range deps[id] {
1651				if !visited[dep] {
1652					if visit(dep) {
1653						return true
1654					}
1655				} else if stack[dep] {
1656					return true
1657				}
1658			}
1659	
1660			stack[id] = false
1661			return false
1662		}
1663	
1664		return visit(startID)
1665	}
